Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "width": 900,
  "height": 460,
  "autosize": "none",
  "padding": 10,

  "data": [
    {
      "name": "dataset"
    },
    {
      "name": "cards",
      "values": [
        {
          "titulo": "Base de Datos",
          "x": 20, "y": 60,
          "bg": "#ffffff", "border": "#e2e8f0", "color": "#0f172a"
        },
        {
          "titulo": "Contactados",
          "x": 310, "y": 60,
          "bg": "#ffffff", "border": "#e2e8f0", "color": "#1e293b"
        },
        {
          "titulo": "Cortaron Comunicación",
          "x": 600, "y": 60,
          "bg": "#fff1f2", "border": "#fecdd3", "color": "#e11d48"
        },
        {
          "titulo": "Interactuaron con Luz",
          "x": 20, "y": 230,
          "bg": "#f0fdf4", "border": "#bbf7d0", "color": "#16a34a"
        },
        {
          "titulo": "Solicitaron Conexión",
          "x": 310, "y": 230,
          "bg": "#ffffff", "border": "#0d9488", "color": "#0f172a"
        },
        {
          "titulo": "Avisarán al Normalizar",
          "x": 600, "y": 230,
          "bg": "#ffffff", "border": "#e2e8f0", "color": "#f59e0b"
        }
      ]
    }
  ],

  "signals": [
    {
      "name": "hasData",
      "update": "length(data(''dataset'')) > 0"
    },
    { "name": "v_Base", "update": "hasData ? data(''dataset'')[0][''Base de Datos''] : 0" },
    { "name": "v_Contactados", "update": "hasData ? data(''dataset'')[0][''Contactados''] : 0" },
    { "name": "v_Cortaron", "update": "hasData ? data(''dataset'')[0][''Cortaron Comunicación''] : 0" },
    { "name": "v_Luz", "update": "hasData ? data(''dataset'')[0][''Interactuaron con Luz''] : 0" },
    { "name": "v_Conexion", "update": "hasData ? data(''dataset'')[0][''Solicitaron Conexión''] : 0" },
    { "name": "v_Normalizar", "update": "hasData ? data(''dataset'')[0][''Avisarán al Normalizar''] : 0" },
    { "name": "p_Contactados", "update": "hasData ? data(''dataset'')[0][''% Contactados''] : 0" },
    { "name": "p_Cortaron", "update": "hasData ? data(''dataset'')[0][''% Cortaron Comunicación''] : 0" },
    { "name": "p_Luz", "update": "hasData ? data(''dataset'')[0][''% Interactuaron con Luz''] : 0" },
    { "name": "p_Conexion", "update": "hasData ? data(''dataset'')[0][''% Solicitaron Conexión''] : 0" },
    { "name": "p_Normalizar", "update": "hasData ? data(''dataset'')[0][''% Avisarán al Normalizar''] : 0" }
  ],

  "marks": [
    {
      "type": "text",
      "encode": {
        "update": {
          "x": { "value": 440 },
          "y": { "value": 20 },
          "align": { "value": "center" },
          "fontSize": { "value": 24 },
          "fontWeight": { "value": "bold" },
          "fill": { "value": "#1e293b" },
          "text": { "value": "Resumen Ejecutivo del Comportamiento (Histórico)" }
        }
      }
    },
    {
      "type": "text",
      "encode": {
        "update": {
          "x": { "value": 440 },
          "y": { "value": 430 },
          "align": { "value": "center" },
          "fontSize": { "value": 14 },
          "fontStyle": { "value": "italic" },
          "fill": { "value": "#64748b" },
          "text": {
            "signal": "''*Todos los porcentajes están calculados sobre el 100% de la Base de Datos Histórica ('' + format(v_Base, '','') + '' clientes).''"
          }
        }
      }
    },
    {
      "type": "rect",
      "from": { "data": "cards" },
      "encode": {
        "update": {
          "x": { "field": "x" },
          "y": { "field": "y" },
          "width": { "value": 260 },
          "height": { "value": 150 },
          "cornerRadius": { "value": 8 },
          "fill": { "field": "bg" },
          "stroke": { "field": "border" },
          "strokeWidth": {
            "signal": "datum.titulo == ''Solicitaron Conexión'' ? 2 : 1"
          }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "cards" },
      "encode": {
        "update": {
          "x": { "signal": "datum.x + 130" },
          "y": { "signal": "datum.y + 55" },
          "align": { "value": "center" },
          "fontSize": { "value": 42 },
          "fontWeight": { "value": "bold" },
          "fill": { "field": "color" },
          "text": {
            "signal": "datum.titulo==''Base de Datos'' ? format(v_Base, '','') : datum.titulo==''Contactados'' ? format(v_Contactados, '','') : datum.titulo==''Cortaron Comunicación'' ? format(v_Cortaron, '','') : datum.titulo==''Interactuaron con Luz'' ? format(v_Luz, '','') : datum.titulo==''Solicitaron Conexión'' ? format(v_Conexion, '','') : format(v_Normalizar, '','')"
          }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "cards" },
      "encode": {
        "update": {
          "x": { "signal": "datum.x + 130" },
          "y": { "signal": "datum.y + 98" },
          "align": { "value": "center" },
          "fontSize": { "value": 16 },
          "fontWeight": { "value": "bold" },
          "fill": { "value": "#475569" },
          "text": { "field": "titulo" }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "cards" },
      "encode": {
        "update": {
          "x": { "signal": "datum.x + 130" },
          "y": { "signal": "datum.y + 125" },
          "align": { "value": "center" },
          "fontSize": { "value": 13 },
          "fill": { "value": "#64748b" },
          "text": {
            "signal": "datum.titulo==''Base de Datos'' ? ''Universo total filtrado'' : (datum.titulo==''Contactados'' ? format(p_Contactados, ''.1%'') : datum.titulo==''Cortaron Comunicación'' ? format(p_Cortaron, ''.1%'') : datum.titulo==''Interactuaron con Luz'' ? format(p_Luz, ''.1%'') : datum.titulo==''Solicitaron Conexión'' ? format(p_Conexion, ''.1%'') : format(p_Normalizar, ''.1%'')) + '' sobre la base total''"
          }
        }
      }
    }
  ]
}'
